import { useEffect, useState } from "react";

const ASTRO = "data:image/png;base64,";

const plusMarks = [
  { top: "12%", left: "48%", color: "#3B7BFF", size: 18 },
  { top: "58%", left: "54%", color: "#FF4C6A", size: 14 },
  { top: "25%", left: "86%", color: "#C840E8", size: 20 },
  { top: "70%", left: "82%", color: "#3B7BFF", size: 12 },
  { top: "75%", left: "62%", color: "#FFE033", size: 16 },
];

function PlusMark({ top, left, color, size, delay }) {
  return (
    <div
      style={{
        position: "absolute", top, left, color,
        fontSize: size, fontWeight: 700,
        opacity: 0,
        animation: "fadeIn 0.6s ease forwards",
        animationDelay: delay,
        lineHeight: 1, userSelect: "none",
      }}
    >+</div>
  );
}

